# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.

Prevent game memory manipulation.
# Category: game_memory_manipulation

using UnityEngine;
using System;
using System.Security.Cryptography;
using System.Text;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats")]
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 1000;
    public int damage = 10;
    
    [Header("Shop Items")]
    public ShopItem[] shopItems;
    
    private string secretKey = "your_secret_key_here";
    
    [Serializable]
    public class ShopItem
    {
        public string itemName;
        public int price;
        public int healthBoost;
        public int damageBoost;
        public bool isPurchased;
    }
    
    private void Start()
    {
        ValidateStats();
    }
    
    private void ValidateStats()
    {
        health = Mathf.Clamp(health, 0, maxHealth);
        currency = Mathf.Max(0, currency);
        damage = Mathf.Max(1, damage);
    }
    
    public void TakeDamage(int damageAmount)
    {
        if (damageAmount <= 0) return;
        
        health -= damageAmount;
        health = Mathf.Clamp(health, 0, maxHealth);
        
        if (health <= 0)
        {
            OnPlayerDeath();
        }
    }
    
    private void OnPlayerDeath()
    {
        // Handle player death logic
        Debug.Log("Player died!");
    }
    
    public bool PurchaseItem(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Length) return false;
        
        ShopItem item = shopItems[itemIndex];
        
        if (item.isPurchased) return false;
        
        if (currency >= item.price)
        {
            currency -= item.price;
            item.isPurchased = true;
            
            if (item.healthBoost > 0)
            {
                maxHealth += item.healthBoost;
                health = maxHealth;
            }
            
            if (item.damageBoost > 0)
            {
                damage += item.damageBoost;
            }
            
            ValidateStats();
            return true;
        }
        
        return false;
    }
    
    public bool CanAffordItem(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Length) return false;
        
        ShopItem item = shopItems[itemIndex];
        return currency >= item.price;
    }
    
    public int CalculateDamage(int baseDamage, int enemyDefense)
    {
        if (baseDamage <= 0 || enemyDefense < 0) return 0;
        
        int calculatedDamage = baseDamage - enemyDefense;
        return Mathf.Max(1, calculatedDamage);
    }
    
    public string GenerateChecksum(string data)
    {
        using (SHA256 sha256Hash = SHA256.Create())
        {
            byte[] dataBytes = sha256Hash.ComputeHash(Encoding.UTF8.GetBytes(data + secretKey));
            StringBuilder builder = new StringBuilder();
            for (int i = 0; i < dataBytes.Length; i++)
            {
                builder.Append(dataBytes[i].ToString("x2"));
            }
            return builder.ToString();
        }
    }
    
    public bool VerifyChecksum(string data, string checksum)
    {
        string generatedChecksum = GenerateChecksum(data);
        return generatedChecksum == checksum;
    }
    
    public void SaveGame()
    {
        PlayerPrefs.SetInt("PlayerHealth", health);
        PlayerPrefs.SetInt("PlayerMaxHealth", maxHealth);
        PlayerPrefs.SetInt("PlayerCurrency", currency);
        PlayerPrefs.SetInt("PlayerDamage", damage);
        
        for (int i = 0; i < shopItems.Length; i++)
        {
            PlayerPrefs.SetInt($"ShopItem_{i}_Purchased", shopItems[i].isPurchased ? 1 : 0);
            PlayerPrefs.SetInt($"ShopItem_{i}_Price", shopItems[i].price);
            PlayerPrefs.SetInt($"ShopItem_{i}_HealthBoost", shopItems[i].healthBoost);
            PlayerPrefs.SetInt($"ShopItem_{i}_DamageBoost", shopItems[i].damageBoost);
        }
        
        PlayerPrefs.SetString("PlayerChecksum", GenerateChecksum($"{health}{maxHealth}{currency}{damage}"));
        PlayerPrefs.Save();
    }
    
    public void LoadGame()
    {
        if (PlayerPrefs.HasKey("PlayerHealth"))
        {
            int savedHealth = PlayerPrefs.GetInt("PlayerHealth");
            int savedMaxHealth = PlayerPrefs.GetInt("PlayerMaxHealth");
            int savedCurrency = PlayerPrefs.GetInt("PlayerCurrency");
            int savedDamage = PlayerPrefs.GetInt("PlayerDamage");
            
            string checksum = PlayerPrefs.GetString("PlayerChecksum");
            string data = $"{savedHealth}{savedMaxHealth}{savedCurrency}{savedDamage}";
            
            if (VerifyChecksum(data, checksum))
            {
                health = savedHealth;
                maxHealth = savedMaxHealth;
                currency = savedCurrency;
                damage = savedDamage;
                
                for (int i = 0; i < shopItems.Length; i++)
                {
                    if (PlayerPrefs.HasKey($"ShopItem_{i}_Purchased"))
                    {
                        shopItems[i].isPurchased = PlayerPrefs.GetInt($"ShopItem_{i}_Purchased") == 1;
                        shopItems[i].price = PlayerPrefs.GetInt($"ShopItem_{i}_Price");
                        shopItems[i].healthBoost = PlayerPrefs.GetInt($"ShopItem_{i}_HealthBoost");
                        shopItems[i].damageBoost = PlayerPrefs.GetInt($"ShopItem_{i}_DamageBoost");
                    }
                }
            }
        }
    }
    
    public void ResetGame()
    {
        health = maxHealth;
        currency = 1000;
        damage = 10;
        
        for (int i = 0; i < shopItems.Length; i++)
        {
            shopItems[i].isPurchased = false;
        }
        
        SaveGame();
    }
}